```solidity
pragma solidity ^0.8.4;

contract TokenAndVotingContract {
    enum State { InactiveVoting, VotingStarted, VotingEnded }

    struct Voter {
        uint256 weight;
        bool voted;
        address delegate;
        uint256 vote;
    }

    struct Candidate {
        string name;
        uint256 votes;
    }

    mapping(address => Voter) public voters;
    mapping(uint256 => Candidate) public candidates;
    uint256 public numCandidates;
    uint256 public borkPool;
    address public winningCandidate;
    State public state;

    event BorksMatched(address indexed recipient);
    event VotingRightsDelegated(address indexed voter, address indexed delegate);
    event DelegatedRightsRemoved(address indexed voter);

    modifier inState(State _state) {
        require(state == _state, "Invalid state");
        _;
    }

    constructor() {
        state = State.InactiveVoting;
    }

    function transfer(address _to, uint256 _amount) external {
        require(balances[msg.sender] >= _amount, "Insufficient balance");
        balances[msg.sender] -= _amount;
        balances[_to] += _amount;
    }

    function enterVote(uint256 _candidateId) external inState(State.VotingStarted) {
        Voter storage sender = voters[msg.sender];
        require(sender.voted == false, "Already voted");
        require(_candidateId < numCandidates, "Invalid candidate");

        sender.vote = _candidateId;
        sender.voted = true;
        candidates[_candidateId].votes++;
    }

    function delegateVoter(address _delegate) external {
        Voter storage sender = voters[msg.sender];
        require(sender.delegate == address(0), "Already delegated");

        while (voters[sender.delegate].delegate != address(0)) {
            sender.delegate = voters[sender.delegate].delegate;
        }

        voters[_delegate].weight += sender.weight;
        emit VotingRightsDelegated(msg.sender, _delegate);
    }

    function proposeBorkPoolRecipient(address _recipient) external inState(State.InactiveVoting) {
        require(borkPool > 0, "No bork pool available");

        if (lockedBorks[_recipient] == 0) {
            lockedBorks[_recipient] = borkPool;
            emit BorksMatched(_recipient);
        }
    }

    function startVoting() external inState(State.InactiveVoting) {
        state = State.VotingStarted;
    }

    function endVoting() external inState(State.VotingStarted) {
        uint256 maxVotes = 0;
        for (uint256 i = 0; i < numCandidates; i++) {
            if (candidates[i].votes > maxVotes) {
                maxVotes = candidates[i].votes;
                winningCandidate = address(i);
            }
        }

        state = State.VotingEnded;
    }

    function removeDelegate() external {
        Voter storage sender = voters[msg.sender];
        require(sender.delegate != address(0), "Not delegated");

        voters[sender.delegate].weight -= sender.weight;
        sender.delegate = address(0);
        emit DelegatedRightsRemoved(msg.sender);
    }

    // Mock variables for demonstration purposes
    mapping(address => uint256) public balances;
    mapping(address => uint256) public lockedBorks;
}
```

